var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"휴가라니요? 당주님, 그게 갑자기 무슨 말씀이십니까?","JPN":"休み？　当主、突然どういうことですか？","ENG":"A vacation? My lady, what are you even talking about?","TWN":"休假？堂主，為何突然要我休假？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유가 부상을 입은 채로 계속 검술수련을 하고 있었다고 나오님께 전해 들었어요.","JPN":"千冬が怪我をしたまま、ずっと剣術の修練をしていたとナオ様からお聞きしました。","ENG":"I heard from Miss Nao that you were training when your wounds are still open.","TWN":"我聽奈緒大人說你受傷還一直在練劍，"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당주를 지켜야 할 호위가 회복에 전념하지 않고 밤새 검을 휘두른다는 것은 마음이 흔들린다는 것.","JPN":"当主を守るべき護衛が回復に専念せず徹夜で修練するというのは、心が揺れている証拠。","ENG":"A warrior wielding her sword instead of focusing on curing herself is a sign of an unstable heart.","TWN":"身為一個該保護堂主的護衛，不顧自己的身體熬夜練劍，就表示你的心在動搖。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러니 내일 하루동안은 마음을 추스를 수 있도록 휴가를 다녀오세요.","JPN":"ですので、明日一日は心を整理できるよう、休みなさい。","ENG":"So please, take a day off tomorrow.","TWN":"所以你明天就好好休息一天，整理一下自己的思緒吧。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그럴 필요는 없습니다. 제가 아니면 누가 당주님을……!","JPN":"その必要はございません。私をおいて誰が当主を……！","ENG":"That won’t be necessary. If not for me, who will–","TWN":"我不需要，除了我還有誰可以保護……！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"걱정 마십시오. 자릴 비우신 동안 제가 목숨을 걸고 당주님을 지키겠습니다.","JPN":"ご心配は無用でございます。千冬様が席を外されている間、私が命をかけてご当主様をお守りいたします。","ENG":"Do not worry. I will protect Lady Nanahara with all my life.","TWN":"請放心，在您休假的這段期間，我會誓死保護堂主。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……예?","JPN":"……はい？","ENG":"...Huh?","TWN":"……可是？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유! 이건 당주의 명입니다! 하루동안 검에 대한 생각은 잊고 휴가를 다녀오세요!","JPN":"千冬！　これは当主の命令です！　一日、剣については考えず、休みなさい！","ENG":"Chifuyu! This is an order! Forget about training and take the day off tomorrow!","TWN":"千冬！這是堂主的命令！我命令你忘掉劍的事，放自己一天假！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……에?","JPN":"……え？","ENG":"...Eh?","TWN":"……什麼？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"저기 벤치 좀 봐. 예쁜 언니가 앉아있어.","JPN":"あのベンチ見て。キレイなお姉さんが座ってるよ。","ENG":"Look at the bench over there. The girl sitting on it is so pretty!","TWN":"你們看椅子那裡，有個漂亮姊姊坐在那。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHILDREN_EXTRA_NULL_NULL","text":{"KOREA":"뭔가 무서워 보이는 칼을 가지고 있어. 가까이 가지 말자.","JPN":"なんか怖そうな刀持ってる。近くに行かない方がいいね。","ENG":"She’s holding some kind of scary looking sword. We should keep our distance from her.","TWN":"她還帶著一把看起來很恐怖的刀欸，不要離她太近啦！"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哀哀……"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님의 명이라고는 하나…… 휴가라는 걸 어찌 보내야 하는 것인지.","JPN":"当主の命令とはいえ……休みというものはどうやって過ごせばいいのだろう。","ENG":"Even if Lady Nanahara gave me orders... I don’t know how to spend free time.","TWN":"說是堂主的命令……但休假對我來說好陌生。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……고작 30분이 지난 것인가?","JPN":"……やっと30分過ぎたのか？","ENG":"...Only 30 minutes passed?","TWN":"……才過30分鐘而已嗎？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"언니, 이거.","JPN":"お姉ちゃん、これあげる。","ENG":"Hi there.","TWN":"姊姊，這給你。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……음? 초콜릿?","JPN":"……む？　チョコレート？","ENG":"...Hmm? Chocolate?","TWN":"……嗯？巧克力？"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"우리 엄마가 그런 무기를 들고 있는 사람들은 도시를 지켜주는 훌륭한 사람들이랬어요.","JPN":"お姉ちゃんみたいに武器を持ってる人は都市を守ってくれる立派な人なんだって、ママから聞いたんだ。","ENG":"Mommy told me that people holding those kinds of weapons are people who keep the city safe.","TWN":"我媽媽說會帶著這種武器的人，都是保護城市的英雄。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};